import{_ as a,o as r,c as t,a2 as i}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Cube","description":"","frontmatter":{},"headers":[],"relativePath":"formats/cube/index.md","filePath":"formats/cube/index.md","lastUpdated":1782025909000}'),o={name:"formats/cube/index.md"};function s(n,e,l,c,d,u){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="cube" tabindex="-1">Cube <a class="header-anchor" href="#cube" aria-label="Permalink to &quot;Cube&quot;">​</a></h1><p>Cube is a Limited format built from a curated pool of Magic cards. Instead of opening retail booster packs, players draft from custom &quot;packs&quot; made from the cube owner&#39;s card pool, then build decks from the cards they drafted. Wizards describes Cube as being like Booster Draft, but with cards pulled from across Magic&#39;s history. <a href="https://magic.wizards.com/en/news/mtg-arena/arena-powered-cube-draft" target="_blank" rel="noreferrer">Source: Arena Powered Cube Draft</a>.</p><p>The cube itself is not a deck. It is the reusable draft environment.</p><h2 id="basic-concept" tabindex="-1">Basic Concept <a class="header-anchor" href="#basic-concept" aria-label="Permalink to &quot;Basic Concept&quot;">​</a></h2><p>A cube is usually a few hundred cards selected by its designer. The designer chooses the themes, power level, colors, archetypes, and constraints. Before a draft, the cube is randomized and divided into draft packs, usually fifteen cards each. Players draft those packs like a normal Booster Draft, build decks, play matches, and return the cards to the cube afterward. <a href="https://magic.wizards.com/en/news/making-magic/power-cubed-2012-11-27" target="_blank" rel="noreferrer">Source: Power, Cubed</a>.</p><p>Most cubes are singleton, meaning they include only one copy of each non-basic-land card. That is common, but not required. Some cubes use duplicates for balance, theme, or to support specific archetypes. Wizards&#39; cube articles describe singleton as typical for many cubes, while also noting variations in cube size, restriction, and structure. <a href="https://magic.wizards.com/en/news/making-magic/power-cubed-2012-11-27" target="_blank" rel="noreferrer">Sources: Power, Cubed</a>, <a href="https://magic.wizards.com/en/news/feature/building-your-first-cube-2016-05-19" target="_blank" rel="noreferrer">Building Your First Cube</a>.</p><h2 id="why-build-a-cube" tabindex="-1">Why Build A Cube? <a class="header-anchor" href="#why-build-a-cube" aria-label="Permalink to &quot;Why Build A Cube?&quot;">​</a></h2><p>Cube lets a group draft the kind of Magic environment they want on demand. It can feel like a greatest-hits Limited format, a nostalgia set, a custom expansion, a high-powered Vintage draft, a peasant environment, a set cube, a Commander draft box, or something much stranger.</p><p>For game-night purposes, cube is useful because the host can prepare the entire experience in advance:</p><ul><li>The card pool.</li><li>The draft structure.</li><li>The land station.</li><li>The number of players supported.</li><li>The intended power level.</li><li>Any house rules or special draft rules.</li></ul><h2 id="common-cube-types" tabindex="-1">Common Cube Types <a class="header-anchor" href="#common-cube-types" aria-label="Permalink to &quot;Common Cube Types&quot;">​</a></h2><ul><li><strong>Powered Cube</strong>: High-powered cards, often including extremely efficient spells and fast mana.</li><li><strong>Unpowered Cube</strong>: Strong cards, but without the most explosive power outliers.</li><li><strong>Peasant Cube</strong>: Only commons and uncommons.</li><li><strong>Pauper Cube</strong>: Only commons.</li><li><strong>Set Cube</strong>: Recreates the feel of drafting a specific Magic set, often with duplicates.</li><li><strong>Theme Cube</strong>: Built around a plane, mechanic, creature type, color restriction, story, or custom design goal.</li><li><strong>Commander Cube</strong>: Drafted for multiplayer Commander-style games, usually with special commander selection rules.</li></ul><h2 id="drafting-and-building" tabindex="-1">Drafting And Building <a class="header-anchor" href="#drafting-and-building" aria-label="Permalink to &quot;Drafting And Building&quot;">​</a></h2><p>The default cube experience mirrors Booster Draft:</p><ul><li>Each player drafts three packs.</li><li>Packs are often fifteen cards.</li><li>Players build minimum forty-card decks.</li><li>Basic lands are supplied separately.</li></ul><p>That default is flexible. Smaller groups might draft more packs, use sealed pools, grid draft, Winston draft, rotisserie draft, or other draft variants. A cube can support whatever draft method the owner wants. Wizards&#39; cube guidance emphasizes that cube size and structure are design choices rather than one fixed template. <a href="https://magic.wizards.com/en/news/feature/building-your-first-cube-2016-05-19" target="_blank" rel="noreferrer">Source: Building Your First Cube</a>.</p><h2 id="boxed-set-notes" tabindex="-1">Boxed-Set Notes <a class="header-anchor" href="#boxed-set-notes" aria-label="Permalink to &quot;Boxed-Set Notes&quot;">​</a></h2><p>A cube box should probably include:</p><ul><li>The cube card pool.</li><li>Basic lands or a land station.</li><li>Draft instructions.</li><li>Player-count guidance.</li><li>Any custom rules or archetype notes.</li><li>Tokens, counters, and helper cards used by the cube.</li><li>A changelog if the cube evolves over time.</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://magic.wizards.com/en/news/feature/building-your-first-cube-2016-05-19" target="_blank" rel="noreferrer">Building Your First Cube</a></li><li><a href="https://magic.wizards.com/en/news/making-magic/power-cubed-2012-11-27" target="_blank" rel="noreferrer">Power, Cubed</a></li><li><a href="https://magic.wizards.com/en/news/mtg-arena/arena-powered-cube-draft" target="_blank" rel="noreferrer">Arena Powered Cube Draft</a></li></ul>',21)])])}const f=a(o,[["render",s]]);export{b as __pageData,f as default};
